import json
from elasticsearch import Elasticsearch

def es_client():
    with open('req.json') as f:
        req = json.load(f)
    
    script = req['script']
    host = 'your-es-host'  # replace with your Elasticsearch host
    port = 9200
    index_name = '_all'
    es = Elasticsearch(hosts=[{'host': host, 'port': port}])
    
    body = {
        "query": {},
        "aggs": {
            req['name']: {
                "scripted_metric": {
                    "init_script" : script,
                    "combine_script": script,
                    "params": {"field": "your-field-name"},
                    "map_script": script
                }
            }
        }
    }
    
    res = es.search(index=index_name, body=body)
    print(res)

es_client()